class SummaryRanges:

    def __init__(self):
        self.parent = {}
        self.rank = {}
        self.start = {}
        self.end = {}

    def find(self, x):
        if x not in self.parent:
            self.parent[x] = x
            self.rank[x] = 0
            self.start[x] = x
            self.end[x] = x
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        rootx = self.find(x)
        rooty = self.find(y)
        if rootx != rooty:
            if self.rank[rootx] > self.rank[rooty]:
                self.parent[rooty] = rootx
                self.start[rootx] = min(self.start[rootx], self.start[rooty])
                self.end[rootx] = max(self.end[rootx], self.end[rooty])
            else:
                self.parent[rootx] = rooty
                self.start[rooty] = min(self.start[rootx], self.start[rooty])
                self.end[rooty] = max(self.end[rootx], self.end[rooty])
                if self.rank[rootx] == self.rank[rooty]:
                    self.rank[rooty] += 1

    def addNum(self, value: int) -> None:
        self.find(value)
        if value - 1 in self.parent:
            self.union(value, value - 1)
        if value + 1 in self.parent:
            self.union(value, value + 1)

    def getIntervals(self) -> List[List[int]]:
        intervals = {}
        for x in self.parent:
            root = self.find(x)
            if root not in intervals:
                intervals[root] = [self.start[root], self.end[root]]
            else:
                intervals[root] = [min(intervals[root][0], self.start[root]), max(intervals[root][1], self.end[root])]
        return sorted(intervals.values())

